class Solution:
    def maxAbsValExpr(self, arr1: List[int], arr2: List[int]) -> int:
        max_a = min_a = arr1[0] + arr2[0] + 0
        max_b = min_b = arr1[0] + arr2[0] - 0
        max_c = min_c = arr1[0] - arr2[0] + 0
        max_d = min_d = arr1[0] - arr2[0] - 0

        for i in range(1, len(arr1)):
            a = arr1[i] + arr2[i] + i
            b = arr1[i] + arr2[i] - i
            c = arr1[i] - arr2[i] + i
            d = arr1[i] - arr2[i] - i

            if a > max_a:
                max_a = a
            if a < min_a:
                min_a = a

            if b > max_b:
                max_b = b
            if b < min_b:
                min_b = b

            if c > max_c:
                max_c = c
            if c < min_c:
                min_c = c

            if d > max_d:
                max_d = d
            if d < min_d:
                min_d = d

        max_diff = max(
            max_a - min_a,
            max_b - min_b,
            max_c - min_c,
            max_d - min_d
        )
        return max_diff

